import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Item, Location } from '../../core/models';

/**
 * Items list — the StockRoom home. Every logged-in user can browse the catalog
 * with computed on-hand totals. `?q=` searches sku/name and `?location=` filters
 * to items stocked at a location; both are bound to query params so views are
 * shareable/deep-linkable. Managers additionally see create/edit actions.
 */
@Component({
  selector: 'app-items-list',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './items-list.component.html',
  styleUrl: './items-list.component.css',
})
export class ItemsListComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly q = signal('');
  readonly locationFilter = signal('');

  readonly locations = signal<Location[]>([
    { id: 'l1', name: 'Main Warehouse', zone: 'A' },
    { id: 'l2', name: 'Storefront', zone: 'B' },
    { id: 'l3', name: 'Overflow Depot', zone: 'C' },
  ]);

  readonly items = signal<Item[]>([
    { id: 'i1', sku: 'SKU-1001', name: 'Steel Bolt M6', unit: 'pcs', reorderAt: 100, onHand: 340,
      stockLevels: [
        { id: 's1', itemId: 'i1', locationId: 'l1', qty: 260 },
        { id: 's2', itemId: 'i1', locationId: 'l2', qty: 80 },
      ] },
    { id: 'i2', sku: 'SKU-1002', name: 'Copper Wire 2mm', unit: 'm', reorderAt: 200, onHand: 85,
      stockLevels: [{ id: 's3', itemId: 'i2', locationId: 'l1', qty: 85 }] },
    { id: 'i3', sku: 'SKU-1003', name: 'PVC Pipe 20mm', unit: 'pcs', reorderAt: 50, onHand: 12,
      stockLevels: [{ id: 's4', itemId: 'i3', locationId: 'l2', qty: 12 }] },
    { id: 'i4', sku: 'SKU-1004', name: 'Wood Screw 40mm', unit: 'pcs', reorderAt: 150, onHand: 620,
      stockLevels: [
        { id: 's5', itemId: 'i4', locationId: 'l1', qty: 400 },
        { id: 's6', itemId: 'i4', locationId: 'l3', qty: 220 },
      ] },
    { id: 'i5', sku: 'SKU-1005', name: 'Aluminium Sheet A4', unit: 'pcs', reorderAt: 30, onHand: 45,
      stockLevels: [{ id: 's7', itemId: 'i5', locationId: 'l1', qty: 45 }] },
    { id: 'i6', sku: 'SKU-1006', name: 'Rubber Gasket 50mm', unit: 'pcs', reorderAt: 80, onHand: 0,
      stockLevels: [] },
    { id: 'i7', sku: 'SKU-1007', name: 'LED Bulb 9W', unit: 'pcs', reorderAt: 40, onHand: 210,
      stockLevels: [
        { id: 's8', itemId: 'i7', locationId: 'l2', qty: 150 },
        { id: 's9', itemId: 'i7', locationId: 'l3', qty: 60 },
      ] },
    { id: 'i8', sku: 'SKU-1008', name: 'Paint Can White 5L', unit: 'cans', reorderAt: 25, onHand: 18,
      stockLevels: [{ id: 's10', itemId: 'i8', locationId: 'l3', qty: 18 }] },
  ]);

  readonly filtered = computed<Item[]>(() => {
    const term = this.q().trim().toLowerCase();
    const loc = this.locationFilter();
    return this.items().filter((it) => {
      const matchesTerm =
        !term || it.sku.toLowerCase().includes(term) || it.name.toLowerCase().includes(term);
      const matchesLoc =
        !loc || (it.stockLevels ?? []).some((s) => s.locationId === loc && s.qty > 0);
      return matchesTerm && matchesLoc;
    });
  });

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.queryParamMap.subscribe((p) => {
      this.q.set(p.get('q') ?? '');
      this.locationFilter.set(p.get('location') ?? '');
    });
  }

  applyFilters(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: {
        q: this.q().trim() || null,
        location: this.locationFilter() || null,
      },
      queryParamsHandling: 'merge',
    });
  }

  clear(): void {
    this.q.set('');
    this.locationFilter.set('');
    this.applyFilters();
  }

  isLow(it: Item): boolean {
    return (it.onHand ?? 0) < it.reorderAt;
  }

  locationName(id: string): string {
    return this.locations().find((l) => l.id === id)?.name ?? id;
  }
}
